// Normalize GitHub issue event to TaskRequest.
// Only process issues labelled 'loop/go' that are NOT 'loop/claimed'.
const body = $input.first().json.body;
const issue = body.issue;
const action = body.action;
if (!issue) throw new Error('Not an issue event');
const labels = (issue.labels || []).map(l => l.name);
if (!labels.includes('loop/go')) return [];
if (labels.includes('loop/claimed')) return [];
if (action !== 'labeled' && action !== 'opened') return [];
const taskId = `i${issue.number}-${Date.now().toString(36)}`;
return [{ json: {
  task_id: taskId,
  issue_number: issue.number,
  repo: body.repository.full_name,
  ref: body.repository.default_branch || 'main',
  intent: issue.body || issue.title,
  title: issue.title,
  source: 'github_issue',
  trigger_id: String(issue.id),
  work_branch: `loop/${taskId}`,
}}];

