const triage = JSON.parse($input.first().json.choices[0].message.content);
const task = $('Normalize TaskRequest').first().json;
const proceed = !!(triage.actionable && triage.in_scope);
return [{ json: { ...task, triage, proceed } }];

// Poll job status every 30s, up to 60 iterations (30 min).
const taskData = $('Build Job YAML').first().json;
const jobName = `loop-${taskData.task_id}`;
const k8sToken = $vars.K8S_SA_TOKEN;
const maxWait = 60;
let jobStatus = 'running';
let outputJson = null;

for (let i = 0; i < maxWait && jobStatus === 'running'; i++) {
  await new Promise(r => setTimeout(r, 30000));
  const resp = await $http.request({
    method: 'GET',
    url: `https://kubernetes.default.svc/apis/batch/v1/namespaces/ai/jobs/${jobName}`,
    headers: { Authorization: `Bearer ${k8sToken}` },
  });
  const conds = resp.status?.conditions || [];
  if (conds.find(c => c.type === 'Complete' && c.status === 'True')) jobStatus = 'complete';
  else if (conds.find(c => c.type === 'Failed' && c.status === 'True')) jobStatus = 'failed';
}

if (jobStatus === 'complete') {
  const podsResp = await $http.request({
    method: 'GET',
    url: `https://kubernetes.default.svc/api/v1/namespaces/ai/pods?labelSelector=loop.68cc.io/task=${taskData.task_id}`,
    headers: { Authorization: `Bearer ${k8sToken}` },
  });
  const pod = (podsResp.items || []).find(p => p.status?.phase === 'Succeeded');
  if (pod) {
    try {
      const log = await $http.request({
        method: 'GET',
        url: `https://kubernetes.default.svc/api/v1/namespaces/ai/pods/${pod.metadata.name}/log?container=runner&tailLines=20`,
        headers: { Authorization: `Bearer ${k8sToken}` },
      });
      const jsonLine = log.trim().split('\n').filter(l => l.startsWith('{')).pop();
      if (jsonLine) outputJson = JSON.parse(jsonLine);
    } catch(e) {}
  }
}

return [{ json: {
  ...taskData,
  job_status: jobStatus,
  output: outputJson || { status: jobStatus === 'complete' ? 'unknown' : jobStatus },
}}];

const pr = $input.first().json;
const task = $('Poll Job').first().json;
const risk = task.triage?.risk || 'medium';
return [{ json: { ...task, pr_number: pr.number, pr_url: pr.html_url, risk, auto_merge: risk === 'low' } }];
